INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (1, 'Teakwood Gallery Frame', 'Handcrafted genuine teakwood with rich natural grain patterns. A warm, timeless classic designed to elevate your photographic prints, sketches, and professional documents.', 1250.00, 'Frames', 'Featured', '/classic_oak_frame.png', FALSE, 1800.00, 4.80, 124, '["/classic_oak_frame.png", "/charcoal_walnut_frame.png"]'::jsonb, '["Hand-selected natural teakwood borders for premium durability and organic aesthetic appeal.", "Supplied with standard high-transmission float glass offering 90%+ optical clarity.", "Includes pre-installed metal hanging brackets for portrait or landscape wall mounting.", "Archival-grade acid-free composition prevents artwork yellowing or discoloration over time."]'::jsonb, '{"Origin": "Handmade in India", "Mount Type": "Wall Hanging / Tabletop convertible", "Profile Width": "0.75 inches", "Frame Material": "Genuine Premium Teakwood", "Hanging Hardware": "Pre-attached D-rings and wiring"}'::jsonb, '[{"date": "14 May 2026", "text": "Stunning organic grain. It makes my gallery print stand out beautifully on the wall!", "author": "Rahul K.", "rating": 5}, {"date": "01 June 2026", "text": "Beautiful wood frame, sturdy mountings. Extremely clean corners.", "author": "Elena S.", "rating": 4}]'::jsonb, 'oak', '#dcd1be', '2026-07-08T09:23:25.490459+05:30', 100, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (3, 'Classic Oak Frame', 'Solid light oak frame with raw matte wax coating. Ideal for minimalist interior designs, landscape photography, watercolors, and charcoal sketches.', 1450.00, 'Frames', 'Hot Seller', '/classic_oak_frame.png', FALSE, 1950.00, 4.70, 94, '["/classic_oak_frame.png", "/charcoal_walnut_frame.png"]'::jsonb, '["Made from 100% genuine sustainable Northern White Oak wood.", "Natural raw finish preserved with light protective organic wax coat.", "Includes scratch-resistant acrylic sheet with high light transmission.", "Double-sealed backing board keeps dust out completely."]'::jsonb, '{"Finish": "Raw Organic Matte", "Origin": "Made in India", "Mount Type": "Wall / Tabletop convertible", "Profile Width": "0.70 inches", "Frame Material": "Genuine White Oak"}'::jsonb, '[{"date": "10 May 2026", "text": "Excellent frame. It matches my scandinavian home decor perfectly. Very organic.", "author": "Karan G.", "rating": 5}]'::jsonb, 'oak', '#dcd1be', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (4, 'Modern Gold Frame', 'Luxury anodized golden aluminum frame. Brushed finish perfect for executive offices, certificates, achievement degrees, and modern fine art statement pieces.', 2400.00, 'Frames', 'Trending', '/modern_gold_frame.png', FALSE, 3200.00, 4.80, 73, '["/modern_gold_frame.png", "/gallery_black_frame.png"]'::jsonb, '["Aerospace-grade anodized aluminum alloy, lightweight yet highly durable.", "Brushed metallic gold finish with polished protective clear lacquer coating.", "Supplied with high-transparency tempered scratch-resistant sheet.", "Sturdy corner joint hardware for perfect alignment."]'::jsonb, '{"Color": "Brushed Luxury Gold", "Origin": "Imported", "Mount Type": "Wall Mounting Only", "Profile Width": "0.50 inches (ultra-slim)", "Frame Material": "Anodized Aluminum Alloy"}'::jsonb, '[{"date": "29 May 2026", "text": "Perfect for framing my university degree. Looks so grand and professional on my office wall.", "author": "Megha D.", "rating": 5}]'::jsonb, 'gold', '#dfba7c', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (5, 'Minimalist White Frame', 'Matte white wooden frame with smooth wrap finish. Beautifully highlights drawings, high-contrast sketching, watercolor paintings, and modern artwork.', 1250.00, 'Frames', 'New Release', '/minimalist_white_frame.png', FALSE, 1600.00, 4.60, 42, '["/minimalist_white_frame.png", "/classic_oak_frame.png"]'::jsonb, '["Medium-density fiberwood core with premium matte white wrap coating.", "Clean corners and edges with no visible joint lines.", "Lightweight and safe for plasterboard or drywalls.", "Includes white backing mat and dust cover sheets."]'::jsonb, '{"Color": "Matte Studio White", "Origin": "Made in India", "Mount Type": "Wall / Tabletop convertible", "Profile Width": "0.75 inches", "Frame Material": "Engineered Pine Wood"}'::jsonb, '[{"date": "12 June 2026", "text": "Matte studio white frame looks extremely neat and elegant. Clean corners.", "author": "Siddharth M.", "rating": 4}]'::jsonb, 'white', '#ffffff', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (15, 'Royal Brass Wax Seal Kit', 'Complete ceremonial letter sealing set containing an ornate carved brass stamp, wax beads, melting spoon, and candles in a leatherette gift box.', 1450.00, 'Stationery', 'Collector', '/wax_seal_kit.png', FALSE, 1950.00, 4.90, 54, '["/wax_seal_kit.png"]'::jsonb, '["Includes 1 wooden handle stamp with 3 interchangeable engraved brass dies (Tree of Life, Rose, Crown).", "Comes with 2 bottles of premium wax seal beads (Deep Gold & Royal Crimson).", "Supplied with solid brass melting spoon and 2 unscented tealight candles.", "Neatly packaged in a vintage leatherette presentation box, perfect for gifting."]'::jsonb, '{"Die Designs": "Tree of Life, Rose, Royal Crown", "Wax Quantity": "Approx. 120 beads per bottle", "Melting Spoon": "Brass with insulated wooden handle", "Box Dimensions": "7.8\" x 5.6\" x 1.6\"", "Stamp Material": "Polished Brass & Rosewood Handle"}'::jsonb, '[{"date": "08 June 2026", "text": "Absolutely spectacular. The wax melts cleanly and seals are crisp. Packaging is beautiful!", "author": "Tanvi J.", "rating": 5}]'::jsonb, NULL, NULL, '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (6, 'Gallery Black Frame', 'Professional matte black wooden finish, perfect for high-contrast statements, gallery exhibitions, and modern black-and-white portraits.', 1300.00, 'Frames', NULL, '/gallery_black_frame.png', FALSE, 1750.00, 4.80, 110, '["/gallery_black_frame.png", "/charcoal_walnut_frame.png"]'::jsonb, '["Solid wood core with satin black protective matte coating.", "Deep frame profile for a dimensional gallery shadowbox appearance.", "High-impact tempered sheet glass protects prints from dust.", "Premium metal suspension bracket pre-attached on the rear."]'::jsonb, '{"Color": "Satin Gallery Black", "Origin": "Made in India", "Mount Type": "Wall Mount", "Profile Width": "0.80 inches", "Frame Material": "Solid Pine Wood"}'::jsonb, '[{"date": "04 June 2026", "text": "Standard exhibition black frame. Very clean and high quality wood. Looks great in my dining room.", "author": "Tanvi R.", "rating": 5}]'::jsonb, 'black', '#1b1b24', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (7, 'Lustre Fine Art Photo Print', 'Premium grade photo prints on heavy 260gsm lustre-finish photographic paper. Delivering vibrant colors, deep blacks, and a gorgeous semi-matte finish that resists fingerprints and reflections.', 350.00, 'Frames', NULL, '/fine_art_print.png', FALSE, 500.00, 4.90, 148, '["/fine_art_print.png", "/fine_art_print.png"]'::jsonb, '["Printed on professional archival-grade 260gsm lustre photographic paper.", "High-fidelity 12-ink printing process ensures stunning detail and color accuracy.", "Ideal for landscapes, wedding portraits, and gallery-style display.", "Archival inks guaranteed not to fade for 100+ years."]'::jsonb, '{"Origin": "Printed in India", "Ink Tech": "12-color archival pigment inks", "Paper Type": "Lustre Archival Photo Paper", "Paper Weight": "260 gsm", "Print Finish": "Semi-matte / Lustre"}'::jsonb, '[{"date": "10 June 2026", "text": "Absolutely stellar printing quality. Colors are incredibly rich and the semi-matte finish is perfect.", "author": "Meera P.", "rating": 5}, {"date": "04 June 2026", "text": "Printed a few high-res landscapes. The details are razor sharp and the paper weight feels solid.", "author": "Aditya S.", "rating": 5}]'::jsonb, 'print', '#ffffff', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (8, 'Elegance 9-Photo Collage Frame', 'A premium large-profile gallery collage frame designed to group nine square family portraits in a beautiful 3x3 layout. Supplied with archival-grade precision bevel-cut matting.', 2850.00, 'Frames', NULL, '/collage_frame.png', FALSE, 3900.00, 4.80, 92, '["/collage_frame.png", "/gallery_black_frame.png"]'::jsonb, '["Heavy-duty gallery black frame profile for structural durability.", "Pristine white multi-aperture mat board holds 9 square photos.", "Tempered anti-scratch float glass protects photos from light fading.", "Supplied with heavy wire mounting kit."]'::jsonb, '{"Origin": "Imported", "Mat Board": "Archival acid-free bevel-cut matting", "Photo Size": "Fits 4\" x 4\" square prints", "Layout style": "9-Photo 3x3 Grid Matrix", "Frame Material": "Satin Black Engineered Wood"}'::jsonb, '[{"date": "02 June 2026", "text": "Best way to frame vacation memories. The matting looks so professional!", "author": "Priyanka K.", "rating": 5}]'::jsonb, 'black', '#1b1b24', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (9, 'Modern Gold Floating Canvas', 'Modern gold metallic float-mount frame designed to give your canvas prints a beautiful border shadowbox look, suspended 0.25 inches off the frame edges.', 2200.00, 'Frames', NULL, '/floating_canvas.png', FALSE, 3000.00, 4.70, 46, '["/floating_canvas.png", "/modern_gold_frame.png"]'::jsonb, '["Gold anodized floating profile creates a deep shadow gap effect.", "Designed specifically for stretched canvas paintings or prints.", "Pre-attached tension brackets suspend canvas inside securely.", "Lightweight aluminum design prevents warping."]'::jsonb, '{"Origin": "Made in India", "Shadow Gap": "0.25 inches around canvas", "Mount style": "Internal float clamp mounts", "Finish style": "Brushed Luxury Gold", "Frame Material": "Anodized Aluminum Alloy"}'::jsonb, '[{"date": "12 June 2026", "text": "Modern looking. The canvas floating look is exactly like art museums.", "author": "Rahul V.", "rating": 4}]'::jsonb, 'gold', '#dfba7c', '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
