 '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (12, 'Handcrafted Leather Journal', 'Hand-tailored rich brown leather cover with a vintage brass key wrap lock. Ideal for daily logging, sketches, and professional notes.', 1850.00, 'Stationery', 'Artisanal', '/leather_journal.png', FALSE, 2500.00, 4.90, 142, '["/leather_journal.png"]'::jsonb, '["Full-grain genuine leather cover that develops a beautiful unique patina over time.", "120 sheets (240 pages) of handmade, acid-free recycled cotton paper.", "Includes built-in leather pen loop and secure brass key strap wrap closure.", "Sturdy hand-stitched binding prevents loose pages."]'::jsonb, '{"Origin": "Handcrafted in Rajasthan", "Dimensions": "8.3\" x 5.8\" (A5 Size)", "Paper Type": "125 GSM Recycled Cotton Paper", "Page Layout": "Unlined / Plain", "Cover Material": "Genuine Full-Grain Leather"}'::jsonb, '[{"date": "12 May 2026", "text": "Stunning craftsmanship. The leather smells genuine and the paper is thick enough for calligraphy.", "author": "Vikram A.", "rating": 5}, {"date": "01 June 2026", "text": "Beautiful vintage design. Paper texture is amazing, although ink bleeds slightly with heavy fountain pens.", "author": "Sophia T.", "rating": 4}]'::jsonb, NULL, NULL, '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
