INSERT INTO "ecommerce"."products" ("id", "name", "description", "price", "category", "badge", "image_url", "out_of_stock", "mrp", "rating", "review_count", "images", "features", "specs", "reviews", "style_id", "hex", "created_at", "available_count", "sku") VALUES (14, 'Solid Walnut Desk Organizer', 'Multi-functional desktop storage slot handcrafted from premium walnut hardwood. Features dedicated smartphone dock, pen slots, and accessory tray.', 1650.00, 'Office & Gifts', 'Best Seller', '/walnut_organizer.png', FALSE, 2100.00, 4.70, 76, '["/walnut_organizer.png"]'::jsonb, '["Carved from a single piece of premium sustainable American Walnut wood.", "Non-slip silicone pads on bottom protect your desk surfaces from scratches.", "Includes dedicated smartphone display slot with charging cable route.", "Features satin wax matte coat to highlight organic wood grain."]'::jsonb, '{"Slots": "1 Phone stand, 3 Pen holes, 1 Letter slot, 1 Tray", "Finish": "Satin Wax Matte Coating", "Origin": "Made in India", "Material": "Solid American Walnut Wood", "Dimensions": "10.2\" L x 4.0\" W x 1.8\" H"}'::jsonb, '[{"date": "29 May 2026", "text": "Very neat organization. Fits my iPhone 15 Pro Max perfectly. Wood grain is gorgeous.", "author": "Amit P.", "rating": 5}]'::jsonb, NULL, NULL, '2026-07-08T09:23:25.490459+05:30', 0, NULL) ON CONFLICT DO NOTHING;
